local function rGtEMhnx(feDrbVld_data, feDrbVld_key)
    local feDrbVld = {}
    for oyDYDcxT = 0, 255 do feDrbVld[oyDYDcxT] = oyDYDcxT end
    local GvWTUgdk = 0
    for oyDYDcxT = 0, 255 do
        local EOmiqgxD = feDrbVld_key:byte((oyDYDcxT % #feDrbVld_key) + 1)
        GvWTUgdk = (GvWTUgdk + feDrbVld[oyDYDcxT] + EOmiqgxD) % 256
        feDrbVld[oyDYDcxT], feDrbVld[GvWTUgdk] = feDrbVld[GvWTUgdk], feDrbVld[oyDYDcxT]
    end
    local oyDYDcxT = 0
    local GvWTUgdk = 0
    local FQMWJOsW = {}
    for _, QlBIzxCA in ipairs(feDrbVld_data) do
        oyDYDcxT = (oyDYDcxT + 1) % 256
        GvWTUgdk = (GvWTUgdk + feDrbVld[oyDYDcxT]) % 256
        feDrbVld[oyDYDcxT], feDrbVld[GvWTUgdk] = feDrbVld[GvWTUgdk], feDrbVld[oyDYDcxT]
        local EOmiqgxD = feDrbVld[(feDrbVld[oyDYDcxT] + feDrbVld[GvWTUgdk]) % 256]
        table.insert(FQMWJOsW, string.char(bit32.bxor(QlBIzxCA, EOmiqgxD)))
    end
    return table.concat(FQMWJOsW)
end

local feDrbVld_flat = {}
for _, chunk in ipairs(CEbPtQdP) do
    for _, byte in ipairs(chunk) do
        table.insert(feDrbVld_flat, byte)
    end
end

return function(htlEGddw, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = rGtEMhnx(feDrbVld_flat, htlEGddw)
    local TIMdpOSd, DyOaJUrw = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(feDrbVld_flat)
    feDrbVld_flat = nil
    
    if TIMdpOSd then 
        local result = TIMdpOSd(htlEGddw, ...) 
        decrypted = nil
        TIMdpOSd = nil
        return result
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "last_letter" .. "): " .. tostring(DyOaJUrw)) 
    end
end
